target.script:

try {
  var igTemp = project.getProperty("ig.temp");
  var igSourceXml = project.getProperty("onGenerate.ig.source") + "xml";
  var xmlFile = new java.io.File(igSourceXml);
  if (xmlFile.exists()) {
    var content = new java.lang.String(java.nio.file.Files.readAllBytes(xmlFile.toPath()), "UTF-8");
    var pattern = java.util.regex.Pattern.compile('<code value="i18n-default-lang"/>\\s*<value value="([^"]+)"');
    var matcher = pattern.matcher(content);
    while (matcher.find()) {
      var lang = matcher.group(1);
      var dir = new java.io.File(igTemp + "/_includes/" + lang);
      dir.mkdirs();
      // menu.xml: find from multiple candidate locations (Sushi may not have copied it yet)
      // toc.xml will be written later by the publisher Java code (createToc).
      var langMenu = new java.io.File(igTemp + "/_includes/" + lang + "/menu.xml");
      if (!langMenu.exists()) {
        var igRoot = project.getProperty("ig.root");
        var menuCandidates = [
          igTemp + "/_includes/menu.xml",
          igRoot + "/fsh-generated/includes/menu.xml",
          igRoot + "/input/includes/menu.xml"
        ];
        for (var j = 0; j < menuCandidates.length; j++) {
          var candidate = new java.io.File(menuCandidates[j]);
          if (candidate.exists()) {
            java.nio.file.Files.copy(candidate.toPath(), langMenu.toPath());
            break;
          }
        }
      }
    }
  }
} catch(e) {
  project.log("ANS: error creating lang include dirs: " + e);
}
